solutions.javascript:
// Solution
function isEven<T>(n: T): n is T & number {
  if (typeof n === 'number' && Number.isInteger(n)) {
    return n % 2 === 0;
  } else {
    return false;
  }
}

function filterEven<T>(arr: T[]): T[] {
  return arr.filter(isEven);
}

solutions.python:
class Solution:
    def isEven(self, n: T) -> bool:
        if isinstance(n, int):
            return n % 2 == 0
        else:
            return False

    def filterEven(self, arr: T[]) -> T[]:
        return [x for x in arr if self.isEven(x) and isinstance(x, int)]
